import{_ as t,o,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"15. Performance Management","description":"","frontmatter":{"title":"15. Performance Management","eba":"Allied Health Professionals 2021-2026","topics":["discipline"]},"headers":[],"relativePath":"ebas/allied-health/consultation-disputes/15-performance-management.md","filePath":"ebas/allied-health/consultation-disputes/15-performance-management.md"}'),a={name:"ebas/allied-health/consultation-disputes/15-performance-management.md"};function s(i,e,p,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_15-performance-management" tabindex="-1">15. Performance Management <a class="header-anchor" href="#_15-performance-management" aria-label="Permalink to &quot;15. Performance Management&quot;">​</a></h1><p><strong>15.1</strong> Application of this clause</p><p><strong>(a)</strong> Where an Employer wishes to deal with performance issues of an Employee, they will be dealt with in accordance with this clause 15 and must be dealt with as soon as practicable following the Employer becoming aware of the performance issue.</p><p><strong>(b)</strong> Where an Employer has concerns about a performance issue that may constitute misconduct (as defined in subclause 16.2(b)), they will be dealt with in accordance with clause 15. A performance issue can be considered misconduct where despite all reasonably practicable interventions by the Employer (which includes following the process in this clause 15) the Employee is unable to fulfil all or part of their job requirements to a satisfactory level. Where this occurs, the performance management process in subclauses 15.3(c)(iv), (d) and (e) will still apply where appropriate.</p><p><strong>15.2</strong> Informal Where the Employer has concerns about an Employee’s performance, the Employer will, wherever appropriate, deal with these concerns through informal discussions with the Employee when these concerns first arise. The Employer will provide a written record of the discussions to the Employee, including a clear outline of the concerns with the Employee’s performance, and support the Employee in rectifying the concerns. The Employee will be given a reasonable opportunity to address the performance concerns.</p><p><strong>15.3</strong> Formal</p><p><strong>(a)</strong> Where the Employee’s work performance is not at an acceptable standard following the process in subclause 15.2 or it was not appropriate to deal with the concerns informally, the Employer may initiate a formal performance management process.</p><p><strong>(b)</strong> The Employer will provide to the Employee in writing:</p><p><strong>(i)</strong> details of the performance concerns including, where relevant, material that supports those concerns; and</p><p><strong>(ii)</strong> notice of the Employee’s right to be represented by a Union or other representative.</p><p><strong>(c)</strong> The Employer will:</p><p><strong>(i)</strong> meet with the Employee and, where relevant, the Employee’s representative, to discuss the concerns;</p><p><strong>(ii)</strong> ensure the Employee is provided with a reasonable opportunity to answer any concerns including a reasonable time to respond;</p><p><strong>(iii)</strong> give genuine consideration to any response or matters raised by an Employee’s response; and</p><p><strong>(iv)</strong> if a performance management plan is proposed, consult with the Employee and the Employee’s representative on the content of the plan.</p><p><strong>(d)</strong> Where, having considered the Employee’s response, the Employer reasonably believes, based on the Employee’s performance, that a performance management plan is appropriate, the Employer will:</p><p><strong>(i)</strong> provide the performance management plan to the Employee in writing following the consultation referred to at subclause 15.3(c)(iv) above, identifying which aspects of the Employee’s performance are unsatisfactory and the required level of performance which must be reasonable; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to address any concerns over a reasonable time.</p><p><strong>(e)</strong> The Employer will provide ongoing feedback on the Employee’s performance during this period, including if the Employee’s performance is not improving to a satisfactory standard, and will provide the Employee with all reasonable support, counselling and training.</p><p><strong>15.4</strong> Preceding Performance issue Where a period of 12 months elapses without the Employee repeating the performance issue, the Employer cannot rely on the preceding performance issue for the purposes of this clause 15 or 16.</p><p><strong>15.5</strong> Disputes A dispute over this clause 15 is to be dealt with in accordance with the Dispute Resolution Procedure of this Agreement (<a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a>).</p><p>Plain language terms: performance review, PIP.</p>',22)])])}const g=t(a,[["render",s]]);export{d as __pageData,g as default};
